// Photos — loaded after page is ready to avoid blocking Supabase init
window._photosReady = false;
window.IMG_RAMBLA = null;
window.IMG_CIUDAD = null;
window.IMG_MVD = null;

function _applyPhotos() {
  window.IMG_RAMBLA = "data:image/jpeg;base64,";
  window.IMG_CIUDAD = "data:image/jpeg;base64,";
  window.IMG_MVD = "data:image/jpeg;base64,";
  window._photosReady = true;
  // Apply to any elements waiting for photos
  if(typeof _applyBgPhotos === 'function') _applyBgPhotos();
}

// Defer photo loading until after DOM + scripts are ready
if(document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function() {
    setTimeout(_applyPhotos, 0);
  });
} else {
  setTimeout(_applyPhotos, 0);
}
